import React, { useState, useEffect } from 'react';
import { db } from '../../utils/firebase';
import { doc, onSnapshot, collection, getDocs, deleteDoc } from 'firebase/firestore';
import { ArrowUpRight, ArrowDownLeft, Calendar, User, Package, Layers, AlertCircle } from 'lucide-react';

export default function MaterialDept() {
  // Purane existing states (workers list management ke liye)
  const [workers, setWorkers] = useState([]);
  const [activeStation, setActiveStation] = useState('platform no 1'); // Jo station select kiya hai
  
  // NEW STATE: Worker se aane wale transaction logs ko store karne ke liye
  const [transactionLogs, setTransactionLogs] = useState([]);
  const [isLoadingLogs, setIsLoadingLogs] = useState(false);

  // 1. REAL-TIME LOGS LISTENER FOR MATERIAL DEPT
  useEffect(() => {
    if (!activeStation) return;

    setIsLoadingLogs(true);
    const cleanKey = activeStation.trim();
    
    // Registry collection se us platform ka doc reference le rahe hain
    const registryDocRef = doc(db, "registry", cleanKey);

    // onSnapshot se real-time data listen kar rahe hain
    const unsubscribe = onSnapshot(registryDocRef, (docSnap) => {
      if (docSnap.exists()) {
        const data = docSnap.data();
        // Agar auditLogs array exist karta hai toh use state mein daalenge aur reverse karenge (latest logs upar dikhane ke liye)
        if (data.auditLogs && Array.isArray(data.auditLogs)) {
          const sortedLogs = [...data.auditLogs].reverse();
          setTransactionLogs(sortedLogs);
        } else {
          setTransactionLogs([]);
        }
      } else {
        setTransactionLogs([]);
      }
      setIsLoadingLogs(false);
    }, (error) => {
      console.error("Error fetching live registry logs:", error);
      setIsLoadingLogs(false);
    });

    return () => unsubscribe();
  }, [activeStation]);

  // UI Engine Styles
  const styles = {
    container: { padding: '24px', backgroundColor: '#F8FAFC', minHeight: '100vh', fontFamily: 'sans-serif' },
    heading: { fontSize: '24px', fontWeight: '700', color: '#0F172A', margin: '0 0 6px 0' },
    subheading: { fontSize: '14px', color: '#64748B', margin: '0 0 24px 0' },
    sectionTitle: { fontSize: '16px', fontWeight: '600', color: '#1E293B', marginBottom: '16px', display: 'flex', alignItems: 'center', gap: '8px' },
    gridLayout: { display: 'grid', gridTemplateColumns: '1fr', gap: '24px' },
    logCard: { backgroundColor: '#FFFFFF', borderRadius: '12px', border: '1px solid #E2E8F0', padding: '20px', boxShadow: '0 1px 3px rgba(0,0,0,0.05)' },
    tableWrapper: { overflowX: 'auto', marginTop: '12px' },
    table: { width: '100%', borderCollapse: 'collapse', textAlign: 'left', fontSize: '14px' },
    th: { backgroundColor: '#F1F5F9', color: '#475569', padding: '12px', fontWeight: '600', borderBottom: '1px solid #E2E8F0' },
    td: { padding: '12px', borderBottom: '1px solid #F1F5F9', color: '#334155', verticalAlign: 'middle' },
    badgeDeposit: { backgroundColor: '#DCFCE7', color: '#15803D', padding: '4px 8px', borderRadius: '6px', fontSize: '12px', fontWeight: '600', display: 'inline-flex', alignItems: 'center', gap: '4px' },
    badgeWithdraw: { backgroundColor: '#FEE2E2', color: '#B91C1C', padding: '4px 8px', borderRadius: '6px', fontSize: '12px', fontWeight: '600', display: 'inline-flex', alignItems: 'center', gap: '4px' },
    previewImg: { width: '45px', height: '45px', borderRadius: '6px', objectFit: 'cover', border: '1px solid #CBD5E1', cursor: 'pointer' }
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.heading}>Material Storage Staff Management (CRUD)</h1>
      <p style={styles.subheading}>Manage hardware storage handling teams & track live station updates.</p>

      {/* --- Purana Input Form & Worker List Base Yahan Rahega --- */}
      
      <div style={{ marginBottom: '24px' }}>
        <label style={{ fontSize: '12px', fontWeight: '700', textTransform: 'uppercase', color: '#64748B', display: 'block', marginBottom: '6px' }}>
          Select Platform View / Configuration Lock
        </label>
        <input 
          type="text" 
          value={activeStation} 
          onChange={(e) => setActiveStation(e.target.value)} 
          style={{ padding: '10px 14px', borderRadius: '8px', border: '1px solid #CBD5E1', width: '250px', fontSize: '14px' }}
          placeholder="e.g., platform no 1"
        />
      </div>

      {/* --- NEW SECTION: LIVE MATERIAL LOGS AUDIT BOARD --- */}
      <div style={styles.gridLayout}>
        <div style={styles.logCard}>
          <h2 style={styles.sectionTitle}>
            <Layers className="w-5 h-5 text-blue-500" /> 
            Live Station Activity Audit Logs for [{activeStation}]
          </h2>

          {isLoadingLogs ? (
            <p style={{ color: '#64748B', fontSize: '14px', textAlign: 'center', padding: '20px' }}>Loading real-time audit matrix...</p>
          ) : transactionLogs.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '30px', color: '#94A3B8', border: '2px dashed #E2E8F0', borderRadius: '8px' }}>
              <AlertCircle className="w-8 h-8 mx-auto mb-2 text-slate-300" />
              <p style={{ fontSize: '14px' }}>Is station node par abhi tak koi transaction entry nahi hui hai.</p>
            </div>
          ) : (
            <div style={styles.tableWrapper}>
              <table style={styles.table}>
                <thead>
                  <tr>
                    <th style={styles.th}>Strategy Mode</th>
                    <th style={styles.th}>Quantity</th>
                    <th style={styles.th}>Operator Session</th>
                    <th style={styles.th}>Timestamp</th>
                    <th style={styles.th} style={{ textAlign: 'center' }}>Verification Proof</th>
                  </tr>
                </thead>
                <tbody>
                  {transactionLogs.map((log, index) => {
                    const isDeposit = log.strategyMode === 'DEPOSIT';
                    return (
                      <tr key={index}>
                        <td style={styles.td}>
                          <span style={isDeposit ? styles.badgeDeposit : styles.badgeWithdraw}>
                            {isDeposit ? <ArrowDownLeft className="w-3.5 h-3.5" /> : <ArrowUpRight className="w-3.5 h-3.5" />}
                            {log.strategyMode}
                          </span>
                        </td>
                        <td style={styles.td} style={{ fontWeight: '700', color: '#0F172A' }}>
                          {log.quantity} Units
                        </td>
                        <td style={styles.td}>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                            <User className="w-4 h-4 text-slate-400" />
                            <span>{log.operatorSession || 'Unknown'}</span>
                          </div>
                        </td>
                        <td style={styles.td}>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '13px', color: '#64748B' }}>
                            <Calendar className="w-4 h-4" />
                            <span>{new Date(log.timestamp).toLocaleString('en-IN')}</span>
                          </div>
                        </td>
                        <td style={styles.td} style={{ textAlign: 'center' }}>
                          {log.verificationPhoto ? (
                            <a href={log.verificationPhoto} target="_blank" rel="noreferrer">
                              <img 
                                src={log.verificationPhoto} 
                                alt="Audit Proof" 
                                style={styles.previewImg} 
                                title="Click to view full screen proof"
                              />
                            </a>
                          ) : (
                            <span style={{ color: '#94A3B8', fontSize: '12px' }}>No Photo</span>
                          )}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>

    </div>
  );
}
